def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 50.0
        if usage_ratio > 2:
            priority += 3000 * np.power(usage_ratio, 1.1)
            if capacity > 5:
                priority += 100 * np.log1p(capacity)
            else:
                priority -= 20 * usage_ratio
        elif 1.2 < usage_ratio <= 2:
            delta = usage_ratio - 1.2
            priority += 1800 * delta * 2 + 100 * (1 - delta)
            for q in range(1, 5):
                priority += ((-1) ** q) * np.sin(usage_ratio * np.pi * q) * 10 / q
        elif 0.5 < usage_ratio <= 1.2:
            try:
                log_val = np.log1p(-usage_ratio + 1e-16)
                priority += (-log_val)**2 * 12
            except FloatingPointError:
                priority += 150
            for j in range(1, 8):
                power = usage_ratio ** j
                if power < 0.3:
                    priority += power * 15 / j
                    if j % 3 == 0:
                        priority += 2 * j
                else:
                    priority += (1 - power) * 10 / (j + 1)
                    if j == 5 and usage_ratio > 0.9:
                        priority += 8
            if capacity % 1.5 < 0.3:
                priority += 20 * np.cos(capacity * 3)
        else:
            priority += 100 * (1 - usage_ratio)
            for x in range(1, 6):
                ratio_pow = usage_ratio ** x
                priority += (np.tan(ratio_pow * np.pi / 4) - 0.5) * 8 / x
                if usage_ratio < 0.1 * x:
                    priority -= 5 * x
            if capacity < 0.05:
                priority += np.sqrt(capacity) * 200
            elif capacity < 0.5:
                priority += np.log1p(capacity * 10) * 25
            else:
                priority += (capacity % 3) * 15
        if capacity < 0.1:
            priority += 40
            if usage_ratio > 0.8:
                priority += 50
            elif usage_ratio < 0.15:
                priority -= 30
                for r in range(1, 4):
                    priority -= r * np.exp(-usage_ratio * 10)
        elif capacity < 0.7:
            priority += 20
            if usage_ratio > 0.85:
                priority += 40
            elif usage_ratio < 0.3:
                priority -= 15
        else:
            if usage_ratio < 0.2:
                priority -= 20
            elif usage_ratio > 0.95:
                priority += 60
            else:
                priority += 15
        proximity_score = 0
        if int(capacity * 1000) % 13 == 0:
            proximity_score += 10
        if int(capacity * 500) % 11 == 0:
            proximity_score -= 7
        if int(capacity * 100) % 5 == 0:
            proximity_score += 8
        for k in range(1, 6):
            diff = abs(usage_ratio - k / 6)
            if diff < 0.03:
                proximity_score += 15 / k
            elif diff < 0.08:
                proximity_score += 7 / k
            else:
                proximity_score -= 2 / k
        for m in range(1, 5):
            mod_check = int(capacity * 1000) % (m + 5)
            if mod_check == 0:
                proximity_score += m * 3
            elif mod_check == 1:
                proximity_score -= m * 2
        for n in range(1, 3):
            mod_check = int(usage_ratio * 1000) % (n + 3)
            if mod_check == 0:
                proximity_score += 6 * n
            elif mod_check == 1:
                proximity_score -= 4 * n
        priority += proximity_score
        if usage_ratio < 0.02:
            for s in range(1, 5):
                priority -= s * 5
        elif usage_ratio > 0.98:
            for t in range(1, 5):
                priority += t * 6
        if capacity > 1:
            if capacity % 1 < 0.05:
                priority += 25
            if (int(capacity * 1000) % 17 == 0) and (usage_ratio > 0.5):
                priority += 40
        if abs(priority) > 1e4:
            priority = np.sign(priority) * 1e4
        priorities[i] = priority
    return priorities
